        return 0

    EPS = 1e-9
    vertices = set()

    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                ax, ay = points[i]
                bx, by = points[j]
                cx, cy = points[k]

                d = 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by))
