                    continue

                ux = ((ax * ax + ay * ay) * (by - cy) +
                      (bx * bx + by * by) * (cy - ay) +
                      (cx * cx + cy * cy) * (ay - by)) / d
                uy = ((ax * ax + ay * ay) * (cx - bx) +
                      (bx * bx + by * by) * (ax - cx) +
